#[cfg(test)]
mod tests {
  use super::*;
  use std::collections::HashSet;

  #[test]
  fn exposes_exactly_53_canonical_binary_properties() {
    let expected: &[&str] = &[
      "ASCII",
      "ASCII_Hex_Digit",
      "Alphabetic",
      "Any",
      "Assigned",
      "Bidi_Control",
      "Bidi_Mirrored",
      "Case_Ignorable",
      "Cased",
      "Changes_When_Casefolded",
      "Changes_When_Casemapped",
      "Changes_When_Lowercased",
      "Changes_When_NFKC_Casefolded",
      "Changes_When_Titlecased",
      "Changes_When_Uppercased",
      "Dash",
      "Default_Ignorable_Code_Point",
      "Deprecated",
      "Diacritic",
      "Emoji",
      "Emoji_Component",
      "Emoji_Modifier",
      "Emoji_Modifier_Base",
      "Emoji_Presentation",
      "Extended_Pictographic",
      "Extender",
      "Grapheme_Base",
      "Grapheme_Extend",
      "Hex_Digit",
      "IDS_Binary_Operator",
      "IDS_Trinary_Operator",
      "ID_Continue",
      "ID_Start",
      "Ideographic",
      "Join_Control",
      "Logical_Order_Exception",
      "Lowercase",
      "Math",
      "Noncharacter_Code_Point",
      "Pattern_Syntax",
      "Pattern_White_Space",
      "Quotation_Mark",
      "Radical",
      "Regional_Indicator",
      "Sentence_Terminal",
      "Soft_Dotted",
      "Terminal_Punctuation",
      "Unified_Ideograph",
      "Uppercase",
      "Variation_Selector",
      "White_Space",
      "XID_Continue",
      "XID_Start",
    ];
    assert_eq!(CANONICAL_BINARY_PROPERTIES.len(), expected.len());
    assert_eq!(expected.len(), 53);
    let mut seen = HashSet::new();
    for (idx, prop) in CANONICAL_BINARY_PROPERTIES.iter().enumerate() {
      assert_eq!(prop.name, expected[idx]);
      assert!(seen.insert(prop.name), "duplicate property {name}", name = prop.name);
      match prop.kind {
        BinaryPropertyKind::Ranges(ranges) => {
          assert!(!ranges.is_empty(), "property {name} has empty table", name = prop.name);
        }
        BinaryPropertyKind::SpecialCase(sc) => match (prop.name, sc) {
          ("Any", BinaryPropertySpecialCase::Any)
          | ("ASCII", BinaryPropertySpecialCase::ASCII)
          | ("Assigned", BinaryPropertySpecialCase::Assigned) => {}
          _ => panic!("unexpected special case mapping for {name}: {sc:?}", name = prop.name),
        },
      }
    }
  }
}
